                    // Add extracted text to context for other rules to use
                    if !context.extracted_media_text.is_empty() {
                        context.extracted_media_text.push_str("\n\n");
                    }
                    context
                        .extracted_media_text
                        .push_str(&media_analysis.extracted_text);
                }
            }
        }
    }
}

