                self.decode_body(&part_body, &part_enc)
            } else {
                part_body
            };
            if part_ct.contains("text/html") {
                return Some(decoded);
            }
            best_part = decoded;
            best_encoding = part_enc;
        }
    }

    if !best_part.is_empty() {
        Some(best_part)
    } else {
        None
    }
}

